frappe.ready(function () {
  var button = document.getElementById("deviceButton");
  var input = document.getElementById("deviceId");
  var error = document.getElementById("errorMessage");

  if (!button || !input) return;

  button.addEventListener("click", function () {
    var value = (input.value || "").trim();

    if (!value) {
      if (error) error.textContent = "Please enter a kitchen device ID.";
      input.focus();
      return;
    }

    if (error) error.textContent = "";

    frappe.call({
      method: "frappe.client.get",
      args: {
        doctype: "Kitchen Device",
        name: value
      },
      callback: function (r) {
        if (r && r.message) {
          var safeValue = encodeURIComponent(value);
          window.location.href = "/kitchen-order-management/" + safeValue;
        } else if (error) {
          error.textContent = "Kitchen device not found.";
        }
      },
      error: function () {
        if (error) error.textContent = "Unable to validate kitchen device.";
      }
    });
  });

  input.addEventListener("input", function () {
    if (error && error.textContent) error.textContent = "";
  });
});

if (frappe.realtime) {
    frappe.realtime.init();
}
const kitchen_device_id = document.getElementById("kitchen_device_id").innerHTML.trim();

// csrf token management
frappe.csrf_token = document.getElementById('csrf_token').value;
$.ajaxSetup({ headers: { 'X-Frappe-CSRF-Token': frappe.csrf_token } });


// check device id is valid
if (!kitchen_device_id) {
    window.alert("kitchen device id not found")
    window.location.href = "/kitchen-id-order";
}

frappe.call({
    method: "frappe.client.get_value",
    args: {
        doctype: "Kitchen Device",
        filters: {
            name: kitchen_device_id
        },
        fieldname: "name"
    },
    callback: function (r) {
        const exists = r && r.message && r.message.name;
        if (!exists) {
            window.alert("kitchen device id not valid")
            window.location.href = "/kitchen-id-order";
        }
    }
});



const posSidebar = document.getElementById("posSidebar");
const posSidebarBody = document.getElementById("posSidebarBody");
const sidebarOverlay = document.getElementById("sidebarOverlay");
const cashierToggle = document.getElementById("cashierToggle");
const sidebarClose = document.getElementById("sidebarClose");

let posProfilesLoaded = false;

function openSidebar() {
    if (!posSidebar) return;
    posSidebar.classList.add("open");
    if (sidebarOverlay) sidebarOverlay.classList.add("visible");
    if (!posProfilesLoaded) {
        loadPosProfiles();
    }
}

function closeSidebar() {
    if (!posSidebar) return;
    posSidebar.classList.remove("open");
    if (sidebarOverlay) sidebarOverlay.classList.remove("visible");
}

if (cashierToggle) {
    cashierToggle.addEventListener("click", function () {
        openSidebar();
    });
}

if (sidebarClose) {
    sidebarClose.addEventListener("click", function () {
        closeSidebar();
    });
}

if (sidebarOverlay) {
    sidebarOverlay.addEventListener("click", function () {
        closeSidebar();
    });
}

function loadPosProfiles() {
    if (!posSidebarBody) return;
    posSidebarBody.innerHTML = "Loading...";
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "POS Profile",
            fields: ["name",],
            filters: {
                enable_kitchen_app: 1,
                custom_kitchen_device: kitchen_device_id
            }
        },
        callback: function (r) {
            const list = r && r.message ? r.message : [];
            posProfilesLoaded = true;
            if (!list.length) {
                posSidebarBody.innerHTML = "<div class=\"sidebar-empty\">No POS Profile found.</div>";
                return;
            }
            posSidebarBody.innerHTML = list.map(function (p) {
                const label = p.title || p.name;
                return '<button class=\"sidebar-item\" data-name=\"' + p.name + '\">' + label + "</button>";
            }).join("");
            const buttons = posSidebarBody.querySelectorAll(".sidebar-item");
            buttons.forEach(function (btn) {
                btn.addEventListener("click", function () {
                    closeSidebar();
                });
            });
        }
    });
}

frappe.realtime.on(`new_kitchen_order_${kitchen_device_id}`, function(data){
    appendOrderCard(data)
})

function appendOrderCard(order){
    const container = document.getElementById(`order-${order.status.toLowerCase()}`)
    if(container){
        container.innerHTML += cardTemplate(order)
    }

    const count = document.getElementById(`count-${order.status.toLowerCase()}`)
    if(count){
        count.innerText = parseInt(count.innerText || 0)+1
    }
}



let currentInvoiceName = null;

function refresh(){
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Kitchen Order",
            fields: ["name", "status", "kitchen_pos_invoice"],
            filters: { 
                status: ["not in", ["Supplied"]],
                "device_id":kitchen_device_id

            }
        },
        callback: (res) => getOrder(res.message || [])
    })
}

function getOrder(orders){
    const stages = ["Received", "Collected", "Ready"];

    stages.forEach(status => {
        const filtered = orders.filter(o => o.status === status)
        const length = filtered.length
        const count = document.getElementById(`count-${status.toLowerCase()}`)
        if(count){
            count.innerText = length;
        }

        const container = document.getElementById(`order-${status.toLowerCase()}`)
        if(container){
            container.innerHTML = filtered.map(item => cardTemplate(item)).join("")
        }
    })
}

const cardTemplate = (order) =>`
<div class="order-card" onClick="openModal('${order.name}','${order.status}','${order.kitchen_pos_invoice}')">
 <b> ${order.name} </b> <br>
 <small> ${order.kitchen_pos_invoice} </small>
 </div>
 `;

 function openModal(name, status, invoice){
    const modal = document.getElementById('modal-container')
    document.getElementById('order-id').innerText = `Order ${name}`
    document.getElementById('order-status').innerText = status
    currentInvoiceName = invoice

    modal.style.display = 'flex';

    frappe.call({
        method: "frappe.client.get",
        args:{
            doctype: "POS Invoice",
            name: invoice
        },
        callback: function(res){
            displayItems(res.message.items || [])
        }
    })

    document.getElementById('btn-next').onclick = () => {
        const stages = ["Received", "Collected", "Ready", "Supplied"]
        const nextStatus = stages[stages.indexOf(status) + 1]

        frappe.call({
            method: "frappe.client.set_value",
            args:{
                doctype: "Kitchen Order",
                name: name,
                fieldname: "status",
                value: nextStatus
            },
            callback: () =>{
                closeModal();
                refresh();
            }
        })
    }
 }

 function displayItems(items){
     const container = document.getElementById("order-items")
     if(container){
         container.innerHTML = items.map(item => `
         <div class="item-row">
         <b>Item:</b> ${item.item_name} - <b>Qty:</b> ${item.qty}
         </div>
         `).join("")
     }
 }

const closeModal = () => {
    document.getElementById('modal-container').style.display = "none";
}

function printInvoice(){
    if(!currentInvoiceName){
        return
    }
    frappe.call({
        method: "kitchen_app.api.get_pos_invoice_print_url",
        args: {
            invoice_name: currentInvoiceName
        },
        callback: function(res){
            if(res.message){
                window.open(res.message, "_blank")
            }
        }
    })
}

refresh()

